import pickle
from sklearn.feature_extraction.text import CountVectorizer
from sklearn.linear_model import LogisticRegression
from flask import Flask, request, jsonify

app = Flask(__name__)

# Load trained model
with open('spam_detection_model.pkl', 'rb') as model_file:
    model = pickle.load(model_file)

# Define CountVectorizer
with open('count_vectorizer.pkl', 'rb') as cv_file:
    cv = pickle.load(cv_file)

@app.route('/predict_spam_probability', methods=['POST'])
def predict_spam_probability():
    data = request.get_json()
    email_text = data['email_text']
    email_text_counts = cv.transform([email_text])
    spam_probability = model.predict_proba(email_text_counts)[:, 1][0]
    
    return jsonify({'spam_probability': spam_probability})

if __name__ == '__main__':
    app.run(debug=True)